# Wire Transfer pytest Test Suite

```python
"""
Wire Transfer Service - pytest Test Suite
Requirement: Customers can initiate wire transfers requiring 2FA;
transfers >$100,000 require manual review.
Negative paths: insufficient funds, unauthorized, exceeded limits.
"""

import pytest
from decimal import Decimal
from unittest.mock import MagicMock, patch, call
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
import uuid


# ---------------------------------------------------------------------------
# Domain models & enums (assumed production interfaces)
# ---------------------------------------------------------------------------

class TransferStatus(str, Enum):
    PENDING_2FA          = "PENDING_2FA"
    PENDING_MANUAL_REVIEW = "PENDING_MANUAL_REVIEW"
    APPROVED             = "APPROVED"
    REJECTED             = "REJECTED"
    FAILED               = "FAILED"


class TransferError(str, Enum):
    INSUFFICIENT_FUNDS    = "INSUFFICIENT_FUNDS"
    UNAUTHORIZED          = "UNAUTHORIZED"
    INVALID_2FA           = "INVALID_2FA"
    EXCEEDED_DAILY_LIMIT  = "EXCEEDED_DAILY_LIMIT"
    EXCEEDED_SINGLE_LIMIT = "EXCEEDED_SINGLE_LIMIT"
    ACCOUNT_FROZEN        = "ACCOUNT_FROZEN"
    INVALID_ACCOUNT       = "INVALID_ACCOUNT"
    TRANSFER_NOT_FOUND    = "TRANSFER_NOT_FOUND"


@dataclass
class Account:
    account_id: str
    owner_id: str
    balance: Decimal
    daily_limit: Decimal      = Decimal("500000.00")
    single_tx_limit: Decimal  = Decimal("250000.00")
    is_frozen: bool           = False
    todays_outflow: Decimal   = Decimal("0.00")


@dataclass
class TransferRequest:
    source_account_id: str
    destination_account_id: str
    amount: Decimal
    currency: str = "USD"
    memo: str     = ""
    requestor_id: str = ""          # authenticated user initiating the transfer


@dataclass
class TransferResult:
    transfer_id: str
    status: TransferStatus
    requires_manual_review: bool = False
    error: Optional[TransferError] = None
    message: str = ""


# ---------------------------------------------------------------------------
# Exceptions (assumed production interfaces)
# ---------------------------------------------------------------------------

class WireTransferException(Exception):
    def __init__(self, error: TransferError, message: str = ""):
        self.error   = error
        self.message = message
        super().__init__(message)


class InsufficientFundsError(WireTransferException):
    def __init__(self):
        super().__init__(TransferError.INSUFFICIENT_FUNDS, "Insufficient funds")


class UnauthorizedError(WireTransferException):
    def __init__(self, message: str = "Unauthorized"):
        super().__init__(TransferError.UNAUTHORIZED, message)


class Invalid2FAError(WireTransferException):
    def __init__(self):
        super().__init__(TransferError.INVALID_2FA, "Invalid or expired 2FA token")


class ExceededDailyLimitError(WireTransferException):
    def __init__(self):
        super().__init__(TransferError.EXCEEDED_DAILY_LIMIT, "Daily transfer limit exceeded")


class ExceededSingleLimitError(WireTransferException):
    def __init__(self):
        super().__init__(TransferError.EXCEEDED_SINGLE_LIMIT, "Single transaction limit exceeded")


class AccountFrozenError(WireTransferException):
    def __init__(self):
        super().__init__(TransferError.ACCOUNT_FROZEN, "Account is frozen")


class InvalidAccountError(WireTransferException):
    def __init__(self, account_id: str):
        super().__init__(TransferError.INVALID_ACCOUNT, f"Invalid account: {account_id}")


# ---------------------------------------------------------------------------
# Service interface (production code under test)
# ---------------------------------------------------------------------------

class TwoFactorService:
    def verify(self, user_id: str, token: str) -> bool: ...          # pragma: no cover


class ManualReviewService:
    def submit(self, transfer_id: str, request: TransferRequest) -> None: ...  # pragma: no cover


class AccountRepository:
    def get(self, account_id: str) -> Account: ...                   # pragma: no cover
    def debit(self, account_id: str, amount: Decimal) -> None: ...   # pragma: no cover


class TransferRepository:
    def save(self, result: TransferResult, request: TransferRequest) -> None: ...  # pragma: no cover
    def get(self, transfer_id: str) -> TransferResult: ...           # pragma: no cover


class WireTransferService:
    MANUAL_REVIEW_THRESHOLD = Decimal("100000.00")

    def __init__(
        self,
        account_repo:   AccountRepository,
        transfer_repo:  TransferRepository,
        two_fa_service: TwoFactorService,
        review_service: ManualReviewService,
    ):
        self._accounts  = account_repo
        self._transfers = transfer_repo
        self._2fa       = two_fa_service
        self._review    = review_service

    def initiate(
        self,
        request: TransferRequest,
        two_fa_token: str,
    ) -> TransferResult:
        # 1. Authorisation
        src = self._accounts.get(request.source_account_id)
        if src is None:
            raise InvalidAccountError(request.source_account_id)
        if src.owner_id != request.requestor_id:
            raise UnauthorizedError("Requestor does not own source account")

        # 2. Account health
        if src.is_frozen:
            raise AccountFrozenError()

        # 3. 2FA
        if not self._2fa.verify(request.requestor_id, two_fa_token):
            raise Invalid2FAError()

        # 4. Limit checks
        if request.amount > src.single_tx_limit:
            raise ExceededSingleLimitError()
        if src.todays_outflow + request.amount > src.daily_limit:
            raise ExceededDailyLimitError()

        # 5. Funds check
        if request.amount > src.balance:
            raise InsufficientFundsError()

        # 6. Destination account validation
        dst = self._accounts.get(request.destination_account_id)
        if dst is None:
            raise InvalidAccountError(request.destination_account_id)

        # 7. Build result
        requires_review = request.amount > self.MANUAL_REVIEW_THRESHOLD
        status = (
            TransferStatus.PENDING_MANUAL_REVIEW
            if requires_review
            else TransferStatus.APPROVED
        )
        result = TransferResult(
            transfer_id=str(uuid.uuid4()),
            status=status,
            requires_manual_review=requires_review,
        )

        # 8. Persist & side-effects
        self._transfers.save(result, request)
        self._accounts.debit(request.source_account_id, request.amount)
        if requires_review:
            self._review.submit(result.transfer_id, request)

        return result


# ===========================================================================
# Fixtures
# ===========================================================================

OWNER_ID      = "user-001"
SOURCE_ACCT   = "acct-src-001"
DEST_ACCT     = "acct-dst-001"
VALID_2FA     = "123456"
INVALID_2FA   = "000000"


@pytest.fixture()
def source_account() -> Account:
    return Account(
        account_id=SOURCE_ACCT,
        owner_id=OWNER_ID,
        balance=Decimal("200000.00"),
        daily_limit=Decimal("500000.00"),
        single_tx_limit=Decimal("250000.00"),
        todays_outflow=Decimal("0.00"),
    )


@pytest.fixture()
def destination_account() -> Account:
    return Account(
        account_id=DEST_ACCT,
        owner_id="user-002",
        balance=Decimal("5000.00"),
    )


@pytest.fixture()
def mock_account_repo(source_account, destination_account) -> MagicMock:
    repo = MagicMock(spec=AccountRepository)
    accounts = {
        SOURCE_ACCT: source_account,
        DEST_ACCT:   destination_account,
    }
    repo.get.side_effect = lambda acct_id: accounts.get(acct_id)
    return repo


@pytest.fixture()
def mock_transfer_repo() -> MagicMock:
    return MagicMock(spec=TransferRepository)


@pytest.fixture()
def mock_2fa_valid() -> MagicMock:
    svc = MagicMock(spec=TwoFactorService)
    svc.verify.return_value = True
    return svc


@pytest.fixture()
def mock_2fa_invalid() -> MagicMock:
    svc = MagicMock(spec=TwoFactorService)
    svc.verify.return_value = False
    return svc


@pytest.fixture()
def mock_review_service() -> MagicMock:
    return MagicMock(spec=ManualReviewService)


@pytest.fixture()
def transfer_service(
    mock_account_repo,
    mock_transfer_repo,
    mock_2fa_valid,
    mock_review_service,
) -> WireTransferService:
    """Default service wired with VALID 2FA."""
    return WireTransferService(
        account_repo=mock_account_repo,
        transfer_repo=mock_transfer_repo,
        two_fa_service=mock_2fa_valid,
        review_service=mock_review_service,
    )


def make_request(amount: str = "1000.00", requestor_id: str = OWNER_ID) -> TransferRequest:
    return TransferRequest(
        source_account_id=SOURCE_ACCT,
        destination_account_id=DEST_ACCT,
        amount=Decimal(amount),
        currency="USD",
        memo="Test transfer",
        requestor_id=requestor_id,
    )


# ===========================================================================
# Test classes
# ===========================================================================

class TestTwoFactorAuthentication:
    """2FA must be verified before any transfer proceeds."""

    def test_valid_2fa_token_allows_transfer(self, transfer_service):
        result = transfer_service.initiate(make_request(), VALID_2FA)
        assert result.status != TransferStatus.FAILED
        assert result.transfer_id

    def test_invalid_2fa_token_raises_error(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_invalid,
        mock_review_service,
    ):
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_invalid, mock_review_service
        )
        with pytest.raises(Invalid2FAError) as exc_info:
            svc.initiate(make_request(), INVALID_2FA)
        assert exc_info.value.error == TransferError.INVALID_2FA

    def test_invalid_2fa_does_not_debit_account(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_invalid,
        mock_review_service,
    ):
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_invalid, mock_review_service
        )
        with pytest.raises(Invalid2FAError):
            svc.initiate(make_request(), INVALID_2FA)
        mock_account_repo.debit.assert_not_called()

    def test_2fa_called_with_correct_user_and_token(self, transfer_service, mock_2fa_valid):
        request = make_request()
        transfer_service.initiate(request, VALID_2FA)
        mock_2fa_valid.verify.assert_called_once_with(OWNER_ID, VALID_2FA)

    def test_invalid_2fa_does_not_persist_transfer(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_invalid,
        mock_review_service,
    ):
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_invalid, mock_review_service
        )
        with pytest.raises(Invalid2FAError):
            svc.initiate(make_request(), INVALID_2FA)
        mock_transfer_repo.save.assert_not_called()


class TestManualReviewThreshold:
    """Transfers > $100,000 must be flagged for manual review."""

    @pytest.mark.parametrize("amount,expects_review", [
        ("100000.00", False),   # exactly at threshold → no review
        ("100000.01", True),    # one cent above → review required
        ("100001.00", True),    # clearly above
        ("250000.00", True),    # max single-tx limit
        ("99999.99",  False),   # just below threshold
        ("50000.00",  False),   # well below threshold
        ("1.00",      False),   # minimum transfer
    ])
    def test_manual_review_threshold_boundary(
        self, transfer_service, amount, expects_review
    ):
        result = transfer_service.initiate(make_request(amount), VALID_2FA)
        assert result.requires_manual_review is expects_review

    @pytest.mark.parametrize("amount,expected_status", [
        ("100000.01", TransferStatus.PENDING_MANUAL_REVIEW),
        ("99999.99",  TransferStatus.APPROVED),
    ])
    def test_transfer_status_reflects_review_requirement(
        self, transfer_service, amount, expected_status
    ):
        result = transfer_service.initiate(make_request(amount), VALID_2FA)
        assert result.status == expected_status

    def test_high_value_transfer_submits_to_review_service(
        self, transfer_service, mock_review_service
    ):
        result = transfer_service.initiate(make_request("150000.00"), VALID_2FA)
        mock_review_service.submit.assert_called_once_with(
            result.transfer_id, pytest.approx(make_request("150000.00"), abs=0)
        )

    def test_low_value_transfer_does_not_submit_to_review_service(
        self, transfer_service, mock_review_service
    ):
        transfer_service.initiate(make_request("50000.00"), VALID_2FA)
        mock_review_service.submit.assert_not_called()

    def test_high_value_transfer_still_debits_account(
        self, transfer_service, mock_account_repo
    ):
        """Debit should happen immediately; manual review is an async approval step."""
        transfer_service.initiate(make_request("150000.00"), VALID_2FA)
        mock_account_repo.debit.assert_called_once_with(SOURCE_ACCT, Decimal("150000.00"))

    def test_transfer_persisted_before_review_submission(
        self, transfer_service, mock_transfer_repo, mock_review_service
    ):
        """Transfer record must exist in DB before the review queue receives it."""
        manager = MagicMock()
        manager.attach_mock(mock_transfer_repo.save,    "save")
        manager.attach_mock(mock_review_service.submit, "submit")

        transfer_service.initiate(make_request("150000.00"), VALID_2FA)

        call_names = [c[0] for c in manager.mock_calls]
        assert call_names.index("save") < call_names.index("submit")


class TestInsufficientFunds:
    """Transfer must be rejected when source account lacks sufficient balance."""

    def test_exact_balance_transfer_is_allowed(self, transfer_service, source_account):
        source_account.balance = Decimal("5000.00")
        result = transfer_service.initiate(make_request("5000.00"), VALID_2FA)
        assert result.status in (TransferStatus.APPROVED, TransferStatus.PENDING_MANUAL_REVIEW)

    def test_transfer_exceeding_balance_raises_error(
        self, transfer_service, source_account
    ):
        source_account.balance = Decimal("999.99")
        with pytest.raises(InsufficientFundsError) as exc_info:
            transfer_service.initiate(make_request("1000.00"), VALID_2FA)
        assert exc_info.value.error == TransferError.INSUFFICIENT_FUNDS

    def test_insufficient_funds_does_not_debit_account(
        self, transfer_service, source_account, mock_account_repo
    ):
        source_account.balance = Decimal("0.00")
        with pytest.raises(InsufficientFundsError):
            transfer_service.initiate(make_request("500.00"), VALID_2FA)
        mock_account_repo.debit.assert_not_called()

    def test_insufficient_funds_does_not_persist_transfer(
        self, transfer_service, source_account, mock_transfer_repo
    ):
        source_account.balance = Decimal("10.00")
        with pytest.raises(InsufficientFundsError):
            transfer_service.initiate(make_request("10.01"), VALID_2FA)
        mock_transfer_repo.save.assert_not_called()

    def test_zero_balance_raises_insufficient_funds(
        self, transfer_service, source_account
    ):
        source_account.balance = Decimal("0.00")
        with pytest.raises(InsufficientFundsError):
            transfer_service.initiate(make_request("0.01"), VALID_2FA)

    def test_negative_amount_edge_case(self, transfer_service, source_account):
        """Negative transfer amounts should not silently bypass balance checks."""
        source_account.balance = Decimal("1000.00")
        # Depending on implementation, expect ValueError or a domain error.
        with pytest.raises((InsufficientFundsError, ValueError, WireTransferException)):
            transfer_service.initiate(make_request("-100.00"), VALID_2FA)


class TestUnauthorizedAccess:
    """Only the account owner may initiate a transfer from that account."""

    def test_owner_can_initiate_transfer(self, transfer_service):
        result = transfer_service.initiate(
            make_request(requestor_id=OWNER_ID), VALID_2FA
        )
        assert result.transfer_id

    def test_non_owner_raises_unauthorized(self, transfer_service):
        with pytest.raises(UnauthorizedError) as exc_info:
            transfer_service.initiate(
                make_request(requestor_id="malicious-user-999"), VALID_2FA
            )
        assert exc_info.value.error == TransferError.UNAUTHORIZED

    def test_unauthorized_user_does_not_debit_account(
        self, transfer_service, mock_account_repo
    ):
        with pytest.raises(UnauthorizedError):
            transfer_service.initiate(
                make_request(requestor_id="hacker-007"), VALID_2FA
            )
        mock_account_repo.debit.assert_not_called()

    def test_unauthorized_check_precedes_2fa(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_valid,
        mock_review_service,
    ):
        """Auth check must happen before 2FA to avoid leaking account existence."""
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_valid, mock_review_service
        )
        with pytest.raises(UnauthorizedError):
            svc.initiate(make_request(requestor_id="attacker"), VALID_2FA)
        # 2FA should NOT be called until the caller is confirmed as the account owner
        mock_2fa_valid.verify.assert_not_called()

    def test_invalid_source_account_raises_error(
        self, transfer_service, mock_account_repo
    ):
        mock_account_repo.get.side_effect = lambda acct_id: (
            None if acct_id == "nonexistent-acct" else mock_account_repo.get.side_effect
        )
        request = TransferRequest(
            source_account_id="nonexistent-acct",
            destination_account_id=DEST_ACCT,
            amount=Decimal("1000.00"),
            requestor_id=OWNER_ID,
        )
        with pytest.raises(InvalidAccountError) as exc_info:
            transfer_service.initiate(request, VALID_2FA)
        assert exc_info.value.error == TransferError.INVALID_ACCOUNT

    def test_frozen_account_raises_error(
        self, transfer_service, source_account
    ):
        source_account.is_frozen = True
        with pytest.raises(AccountFrozenError) as exc_info:
            transfer_service.initiate(make_request(), VALID_2FA)
        assert exc_info.value.error == TransferError.ACCOUNT_FROZEN


class TestExceededLimits:
    """Transfers violating single-transaction or daily limits must be rejected."""

    def test_transfer_at_single_tx_limit_is_allowed(
        self, transfer_service, source_account
    ):
        source_account.single_tx_limit = Decimal("250000.00")
        result = transfer_service.initiate(make_request("250000.00"), VALID_2FA)
        assert result.status == TransferStatus.PENDING_MANUAL_REVIEW

    def test_transfer_above_single_tx_limit_raises_error(
        self, transfer_service, source_account
    ):
        source_account.single_tx_limit = Decimal("250000.00")
        with pytest.raises(ExceededSingleLimitError) as exc_info:
            transfer_service.initiate(make_request("250000.01"), VALID_2FA)
        assert exc_info.value.error == TransferError.EXCEEDED_SINGLE_LIMIT

    def test_single_tx_limit_check_does_not_debit(
        self, transfer_service, source_account, mock_account_repo
    ):
        source_account.single_tx_limit = Decimal("100.00")
        with pytest.raises(ExceededSingleLimitError):
            transfer_service.initiate(make_request("100.01"), VALID_2FA)
        mock_account_repo.debit.assert_not_called()

    def test_daily_limit_not_exceeded(self, transfer_service, source_account):
        source_account.todays_outflow = Decimal("400000.00")
        source_account.daily_limit    = Decimal("500000.00")
        result = transfer_service.initiate(make_request("100000.00"), VALID_2FA)
        assert result.status in (TransferStatus.APPROVED, TransferStatus.PENDING_MANUAL_REVIEW)

    def test_daily_limit_exceeded_raises_error(
        self, transfer_service, source_account
    ):
        source_account.todays_outflow = Decimal("450000.00")
        source_account.daily_limit    = Decimal("500000.00")
        with pytest.raises(ExceededDailyLimitError) as exc_info:
            transfer_service.initiate(make_request("50000.01"), VALID_2FA)
        assert exc_info.value.error == TransferError.EXCEEDED_DAILY_LIMIT

    def test_daily_limit_exactly_met_is_allowed(
        self, transfer_service, source_account
    ):
        source_account.todays_outflow = Decimal("400000.00")
        source_account.daily_limit    = Decimal("500000.00")
        result = transfer_service.initiate(make_request("100000.00"), VALID_2FA)
        assert result.transfer_id

    def test_daily_limit_check_does_not_debit(
        self, transfer_service, source_account, mock_account_repo
    ):
        source_account.todays_outflow = Decimal("490000.00")
        source_account.daily_limit    = Decimal("500000.00")
        with pytest.raises(ExceededDailyLimitError):
            transfer_service.initiate(make_request("10000.01"), VALID_2FA)
        mock_account_repo.debit.assert_not_called()

    @pytest.mark.parametrize("outflow,amount,should_raise", [
        ("0.00",      "500000.00", False),   # exact daily limit
        ("0.01",      "500000.00", True),    # one cent over when combined
        ("499999.99", "0.01",      False),   # one cent remaining
        ("500000.00", "0.01",      True),    # daily limit already exhausted
    ])
    def test_daily_limit_parametrized(
        self, transfer_service, source_account, outflow, amount, should_raise
    ):
        source_account.todays_outflow = Decimal(outflow)
        source_account.daily_limit    = Decimal("500000.00")
        source_account.single_tx_limit = Decimal("500000.00")
        if should_raise:
            with pytest.raises(ExceededDailyLimitError):
                transfer_service.initiate(make_request(amount), VALID_2FA)
        else:
            result = transfer_service.initiate(make_request(amount), VALID_2FA)
            assert result.transfer_id


class TestTransferHappyPath:
    """End-to-end happy path checks."""

    def test_standard_transfer_returns_transfer_id(self, transfer_service):
        result = transfer_service.initiate(make_request("1000.00"), VALID_2FA)
        assert result.transfer_id
        assert len(result.transfer_id) > 0

    def test_standard_transfer_is_approved(self, transfer_service):
        result = transfer_service.initiate(make_request("1000.00"), VALID_2FA)
        assert result.status == TransferStatus.APPROVED

    def test_transfer_is_persisted(self, transfer_service, mock_transfer_repo):
        result = transfer_service.initiate(make_request("1000.00"), VALID_2FA)
        mock_transfer_repo.save.assert_called_once()
        saved_result, saved_request = mock_transfer_repo.save.call_args[0]
        assert saved_result.transfer_id == result.transfer_id

    def test_account_is_debited_correct_amount(
        self, transfer_service, mock_account_repo
    ):
        transfer_service.initiate(make_request("7500.00"), VALID_2FA)
        mock_account_repo.debit.assert_called_once_with(SOURCE_ACCT, Decimal("7500.00"))

    def test_unique_transfer_ids_per_call(self, transfer_service):
        result_a = transfer_service.initiate(make_request("100.00"), VALID_2FA)
        result_b = transfer_service.initiate(make_request("200.00"), VALID_2FA)
        assert result_a.transfer_id != result_b.transfer_id


class TestErrorOrdering:
    """
    Guards must fire in the correct order so that earlier failures
    do not leak information about later checks.
    """

    def test_unauthorized_error_before_insufficient_funds(
        self, transfer_service, source_account
    ):
        source_account.balance = Decimal("0.00")   # would also fail funds check
        with pytest.raises(UnauthorizedError):
            transfer_service.initiate(
                make_request(requestor_id="intruder"), VALID_2FA
            )

    def test_frozen_account_error_before_2fa(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_invalid,
        mock_review_service,
        source_account,
    ):
        """Frozen account check must surface even when 2FA would also fail."""
        source_account.is_frozen = True
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_invalid, mock_review_service
        )
        with pytest.raises(AccountFrozenError):
            svc.initiate(make_request(), INVALID_2FA)

    def test_2fa_failure_before_limit_checks(
        self,
        mock_account_repo,
        mock_transfer_repo,
        mock_2fa_invalid,
        mock_review_service,
        source_account,
    ):
        """2FA must be verified before expensive limit/funds checks."""
        source_account.single_tx_limit = Decimal("500.00")  # would also fail limit
        svc = WireTransferService(
            mock_account_repo, mock_transfer_repo, mock_2fa_invalid, mock_review_service
        )
        with pytest.raises(Invalid2FAError):
            svc.initiate(make_request("1000.00"), INVALID_2FA)
